/**
 * Maps a 384-dim embedding vector to an HSL color string.
 * Uses the first 3 dimensions (normalized) to derive Hue, Saturation, and Lightness.
 * Returns null if no valid embedding is provided.
 */
const sigmoid = (x) => 1 / (1 + Math.exp(-x));

const embeddingToColor = (embedding) => {
    if (!Array.isArray(embedding) || embedding.length < 3) return null;

    const h = Math.round(sigmoid(embedding[0]) * 360);
    const s = Math.round(40 + sigmoid(embedding[1]) * 40);   // 40–80%
    const l = Math.round(30 + sigmoid(embedding[2]) * 30);   // 30–60%

    return `hsl(${h}, ${s}%, ${l}%)`;
};

export default embeddingToColor;

