                y: galaxy.y,
                radius,
                color,
                userId: galaxy.userId,
            });
        }

        return data;
    }, [galaxies, centroids]);

    // Initialize per-cloud rotation offsets when data changes
    useEffect(() => {
        animRef.current.rotations = nebulaData.map(() => Math.random() * 360);
    }, [nebulaData]);

    // Breathing animation loop
    const animate = useCallback(() => {
        const anim = animRef.current;
        anim.phase = (performance.now() % BREATH_PERIOD) / BREATH_PERIOD;

        for (let i = 0; i < anim.rotations.length; i++) {
            anim.rotations[i] += ROTATION_SPEED;
        }

        if (shapeRef.current) {
            shapeRef.current.getLayer()?.batchDraw();
        }

        rafRef.current = requestAnimationFrame(animate);
    }, []);

    useEffect(() => {
        rafRef.current = requestAnimationFrame(animate);
        return () => {
            if (rafRef.current) cancelAnimationFrame(rafRef.current);
        };
    }, [animate]);

