                        const cloud = nebulaData[i];
                        const rot = (anim.rotations[i] || 0) * (Math.PI / 180);
                        const r = cloud.radius * scale;

                        ctx.save();
                        ctx.translate(cloud.x, cloud.y);
                        ctx.rotate(rot);

                        const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, r);
                        grad.addColorStop(0, cloud.color.replace(')', ', 0.18)').replace('hsl(', 'hsla(').replace('rgb(', 'rgba('));
                        grad.addColorStop(0.5, cloud.color.replace(')', ', 0.08)').replace('hsl(', 'hsla(').replace('rgb(', 'rgba('));
                        grad.addColorStop(1, 'rgba(0,0,0,0)');

                        ctx.beginPath();
                        ctx.arc(0, 0, r, 0, TWO_PI);
                        ctx.fillStyle = grad;
                        ctx.fill();

                        ctx.restore();
