    computeSectorKey,
    getNeighborSectorKeys,
} from './utils/cosmicPhysics';
import { handleClickProfile } from '../../../helpers/handleClicks';
import styles from './Universe.module.css';

const SECTOR_SIZE = 2000;
const ENABLE_SETTLED_RPC_SAVE = import.meta.env.VITE_ENABLE_UNIVERSE_SETTLE_SAVE === 'true';

const Universe = () => {
    const navigate = useNavigate();
    const { user } = useAuth();
    const userId = user?.userData?.[0]?.id || null;

    const fetchDebounceRef = useRef(null);
    const settleDebounceRef = useRef(null);
    const lastSettledPayloadRef = useRef('');
    const initialFetchResolvedRef = useRef(false);
    const hasAutoFocusedOwnGalaxyRef = useRef(false);
    const ownGalaxyLookupStartedRef = useRef(false);

    const [posts, setPosts] = useState(new Map());
    const [selectedPost, setSelectedPost] = useState(null);
    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
    const [galaxyProfile, setGalaxyProfile] = useState(null);
    const [pulsingId, setPulsingId] = useState(null);
    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [ownGalaxyTarget, setOwnGalaxyTarget] = useState(null);

    // Gravity data from server (fallback paths when embeddings are unavailable in payload)
    const [centroids, setCentroids] = useState([]);
    const [galaxyEdges, setGalaxyEdges] = useState([]);
    const [similarPairs, setSimilarPairs] = useState([]);
    const [starPulls, setStarPulls] = useState([]);

    const {
        stageRef, stageSize, camera, zoom, isDragging, centerWorld,
        getLayerProps, getViewportBounds, stageEvents, flyTo, jumpTo, isFlying,
    } = useUniverseCamera(userId, hasOwnPosts);

    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
    const showTitles = zoom > 0.5;

    // Sector partitioning for scalable local gravity math.
    const postSectorIndex = useMemo(() => (
        buildSectorIndex(
            postArray,
            (post) => ({
                x: post?.display_x ?? post?.universe_x,
                y: post?.display_y ?? post?.universe_y,
            }),
            SECTOR_SIZE
        )
    ), [postArray]);

    const centerSectorKey = useMemo(
        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
        [centerWorld.x, centerWorld.y]
    );

    const activeSectorKeys = useMemo(
        () => new Set(getNeighborSectorKeys(centerSectorKey)),
        [centerSectorKey]
    );

    const activePosts = useMemo(() => {
        if (activeSectorKeys.size === 0) return postArray;

        const next = [];
        for (const key of activeSectorKeys) {
            const bucket = postSectorIndex.get(key);
            if (bucket?.length) next.push(...bucket);
        }
        return next;
    }, [postArray, postSectorIndex, activeSectorKeys]);

    const activePostIds = useMemo(() => {
        const ids = new Set();
        for (const post of activePosts) {
            if (post?.id) ids.add(post.id);
        }
        return ids;
    }, [activePosts]);

    const { centroidByUser } = useMemo(
        () => computeGalaxyCentroids(postArray),
        [postArray]
    );

    // ── Hash-based galaxies (STARTING positions — always from hash) ──
    const hashGalaxies = useMemo(() => {
        const seen = new Map();
        for (const post of postArray) {
            const uid = post.users?.id ?? post.user_id;
            if (!uid || seen.has(uid)) continue;
            const hash = userHomeCoords(uid);
            seen.set(uid, {
                userId: uid,
                name: post.users?.name ?? post.user_name ?? 'Anonymous',
                x: hash.x,
                y: hash.y,
            });
        }
        return Array.from(seen.values());
    }, [postArray]);

    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
    const centroidTargets = useMemo(() => {
        const map = new Map();
        for (const c of centroids) {
            if (c.galaxy_x != null && c.galaxy_y != null) {
                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
            }
        }
        return map;
    }, [centroids]);

    // ── Gravity hook: animates galaxies + computes star pull offsets ─
    const {
        galaxyPositions,
        starPullOffsets,
        isSettled,
        galaxyEdges: effectiveGalaxyEdges,
        hasEmbeddingGravity,
    } = useCosmicGravity({
        galaxies: hashGalaxies,
        centroidTargets,
        edges: galaxyEdges,
        posts: postArray,
        starPulls,
        centroidByUser,
        activeSectorKeys,
        activePostIds,
        sectorSize: SECTOR_SIZE,
    });

    // ── Render galaxies = hash galaxies with animated positions ──────
    const galaxies = useMemo(() => {
        return hashGalaxies.map(g => {
            const animated = galaxyPositions.get(g.userId);
            return animated ? { ...g, x: animated.x, y: animated.y } : g;
        });
    }, [hashGalaxies, galaxyPositions]);

    const getComputedStarPosition = useCallback((post) => {
        if (!post) return null;

        const uid = post.users?.id ?? post.user_id;
        const hashGal = userHomeCoords(uid);
        const animGal = galaxyPositions.get(uid);
        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
        const pull = starPullOffsets.get(post.id);

        const baseX = post.universe_x ?? post.display_x;
        const baseY = post.universe_y ?? post.display_y;
        if (baseX == null || baseY == null) return null;

        return {
            x: baseX + galDx + (pull?.dx ?? 0),
            y: baseY + galDy + (pull?.dy ?? 0),
        };
    }, [galaxyPositions, starPullOffsets]);

    // Resolve logged-in user's galaxy target independently from viewport data.
    useEffect(() => {
        if (!userId) return;
        if (ownGalaxyLookupStartedRef.current) return;

        ownGalaxyLookupStartedRef.current = true;
        let cancelled = false;

        const resolveOwnGalaxyTarget = async () => {
            try {
                const { data, error } = await supabase
                    .from('galaxy_centroids')
                    .select('galaxy_x, galaxy_y')
                    .eq('user_id', userId)
                    .maybeSingle();

                if (cancelled) return;

                if (!error && data?.galaxy_x != null && data?.galaxy_y != null) {
                    setOwnGalaxyTarget({ x: data.galaxy_x, y: data.galaxy_y });
                    setHasOwnPosts(true);
                    return;
                }
            } catch (err) {
                console.warn('[universe] own centroid lookup failed:', err?.message || err);
            }

            if (!cancelled) {
                setOwnGalaxyTarget(userHomeCoords(userId));
            }
        };

        resolveOwnGalaxyTarget();

        return () => {
            cancelled = true;
        };
    }, [userId]);

