 767→export const getCanvasGalleryService = async(limit = CANVAS_GALLERY_LIMIT_DEFAULT, userId, sort = 'hottest', cursor = null) => {
 768→    if(isNaN(limit) || limit < 1 || limit > CANVAS_GALLERY_LIMIT_MAX){
 769→        throw {status: 400, error: `limit should be an integer between 1 and ${CANVAS_GALLERY_LIMIT_MAX}`};
 770→    }
 771→
 772→    const parsedLimit = parseInt(limit);
 773→    const normalizedSort = typeof sort === 'string' ? sort.toLowerCase().trim() : 'hottest';
 774→    const isNewest = normalizedSort === 'newest';
 775→    const parsedCursor = parseCanvasGalleryCursor(cursor, isNewest ? 'newest' : 'hottest');
 776→    const cursorOffset = parsedCursor.offset;
 777→
 778→    const baseQuery = supabase
 779→        .from('journals')
 780→        .select(`
 781→            *,
 782→            users(*),
 783→            like_count: likes(count),
 784→            comment_count: comments(count),
 785→            bookmark_count: bookmarks(count),
 786→            stamp_count: canvas_stamps(count),
 787→            margin_count: canvas_margin_items(count)
 788→        `)
 789→        .eq('privacy', 'public')
 790→        .eq('post_type', 'canvas')
 791→        .order('created_at', {ascending: false})
 792→        .order('id', {ascending: false});
 793→
 794→    const {data: journals, error: journalsError} = isNewest
 795→        ? await baseQuery.range(cursorOffset, cursorOffset + parsedLimit)
 796→        : await baseQuery.limit(CANVAS_GALLERY_HOT_FETCH_LIMIT);
 797→
 798→    if(journalsError){
 799→        console.error('supabase error while fetching canvas gallery journals:', journalsError.message);
 800→        throw {status: 500, error: 'supabase error while fetching canvas gallery journals'};
 801→    }
 802→
 803→    const enrichedJournals = await attachUserInteractionFlags(journals || [], userId);
 804→    const normalizedJournals = enrichedJournals.map((journal) => ({
 805→        ...journal,
 806→        hot_score: scoreJournalHotness(journal)
 807→    }));
 808→
 809→    if(!isNewest){
 810→        normalizedJournals.sort((a, b) => {
 811→            const scoreDiff = (b.hot_score || 0) - (a.hot_score || 0);
 812→            if(scoreDiff !== 0){
 813→                return scoreDiff;
 814→            }
 815→
 816→            const dateDiff = new Date(b?.created_at || 0) - new Date(a?.created_at || 0);
 817→            if(dateDiff !== 0){
 818→                return dateDiff;
 819→            }
 820→
 821→            return (b?.id || 0) - (a?.id || 0);
 822→        });
 823→    }
 824→
 825→    const paginatedJournals = isNewest
 826→        ? normalizedJournals
 827→        : normalizedJournals.slice(cursorOffset, cursorOffset + parsedLimit + 1);
 828→    const hasMore = paginatedJournals.length > parsedLimit;
 829→    const data = hasMore ? paginatedJournals.slice(0, parsedLimit) : paginatedJournals;
 830→    const nextCursor = hasMore
 831→        ? encodeCanvasGalleryCursor(cursorOffset + data.length, isNewest ? 'newest' : 'hottest')
 832→        : null;
 833→
 834→    return {
 835→        data: data,
 836→        sort: isNewest ? 'newest' : 'hottest',
 837→        totalCandidates: normalizedJournals.length,
 838→        hasMore: hasMore,
 839→        nextCursor: nextCursor
 840→    };
 841→}
