229→                const result = await getUniversePosts(
230→                    bounds.minX,
231→                    bounds.maxX,
232→                    bounds.minY,
233→                    bounds.maxY,
234→                    200
235→                );
236→                if (result?.data) {
237→                    setPosts(prev => {
238→                        const next = new Map(prev);
