 18→export default function useCosmicGravity({
 19→    galaxies,
 20→    centroidTargets,
 21→    edges,
 22→    posts,
 23→    starPulls,
 24→    centroidByUser,
 25→    activeSectorKeys,
 26→    activePostIds,
 27→    sectorSize = 2000,
 28→}) {
 29→    const [galaxyPositions, setGalaxyPositions] = useState(new Map());
