  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts, getUserData } from '../../../API/Api';
  6→import supabase from '../../utils/supabaseClient';
  7→import useUniverseCamera from './hooks/useUniverseCamera';
  8→import useCosmicGravity from './hooks/useCosmicGravity';
  9→import DeepSpaceLayer from './layers/DeepSpaceLayer';
 10→import MidGalaxyLayer from './layers/MidGalaxyLayer';
 11→import NebulaLayer from './layers/NebulaLayer';
 12→import InteractiveLayer from './layers/InteractiveLayer';
 13→import UniverseMinimap from './components/UniverseMinimap';
 14→import { extractSnippet, MIN_UNIVERSE_ZOOM, userHomeCoords } from './utils/starUtils';
 15→import {
 16→    buildSectorIndex,
 17→    computeGalaxyCentroids,
 18→    computeSectorKey,
 19→    getNeighborSectorKeys,
 20→} from './utils/cosmicPhysics';
 21→import { handleClickProfile } from '../../../helpers/handleClicks';
 22→import styles from './Universe.module.css';
 23→
 24→const SECTOR_SIZE = 2000;
 25→const ENABLE_SETTLED_RPC_SAVE = import.meta.env.VITE_ENABLE_UNIVERSE_SETTLE_SAVE === 'true';
 26→
 27→const Universe = () => {
 28→    const navigate = useNavigate();
 29→    const { user } = useAuth();
 30→    const userId = user?.userData?.[0]?.id || null;
 31→
 32→    const fetchDebounceRef = useRef(null);
 33→    const settleDebounceRef = useRef(null);
 34→    const lastSettledPayloadRef = useRef('');
 35→    const initialFetchResolvedRef = useRef(false);
 36→    const hasAutoFocusedOwnGalaxyRef = useRef(false);
 37→    const ownGalaxyLookupStartedRef = useRef(false);
 38→
 39→    const [posts, setPosts] = useState(new Map());
 40→    const [selectedPost, setSelectedPost] = useState(null);
 41→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 42→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 43→    const [pulsingId, setPulsingId] = useState(null);
 44→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 45→    const [isInitialLoading, setIsInitialLoading] = useState(true);
 46→    const [ownGalaxyTarget, setOwnGalaxyTarget] = useState(null);
 47→
 48→    // Gravity data from server (fallback paths when embeddings are unavailable in payload)
 49→    const [centroids, setCentroids] = useState([]);
 50→    const [galaxyEdges, setGalaxyEdges] = useState([]);
 51→    const [similarPairs, setSimilarPairs] = useState([]);
 52→    const [starPulls, setStarPulls] = useState([]);
 53→
 54→    const {
 55→        stageRef, stageSize, camera, zoom, isDragging, centerWorld,
 56→        getLayerProps, getViewportBounds, stageEvents, flyTo, jumpTo, isFlying,
 57→    } = useUniverseCamera(userId, hasOwnPosts);
 58→
 59→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 60→    const showTitles = zoom > 0.5;
 61→
 62→    // Sector partitioning for scalable local gravity math.
 63→    const postSectorIndex = useMemo(() => (
 64→        buildSectorIndex(
 65→            postArray,
 66→            (post) => ({
 67→                x: post?.display_x ?? post?.universe_x,
 68→                y: post?.display_y ?? post?.universe_y,
 69→            }),
 70→            SECTOR_SIZE
 71→        )
 72→    ), [postArray]);
 73→
 74→    const centerSectorKey = useMemo(
 75→        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
 76→        [centerWorld.x, centerWorld.y]
 77→    );
 78→
 79→    const activeSectorKeys = useMemo(
 80→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
 81→        [centerSectorKey]
 82→    );
 83→
 84→    const activePosts = useMemo(() => {
 85→        if (activeSectorKeys.size === 0) return postArray;
 86→
 87→        const next = [];
 88→        for (const key of activeSectorKeys) {
 89→            const bucket = postSectorIndex.get(key);
 90→            if (bucket?.length) next.push(...bucket);
 91→        }
 92→        return next;
 93→    }, [postArray, postSectorIndex, activeSectorKeys]);
 94→
 95→    const activePostIds = useMemo(() => {
 96→        const ids = new Set();
 97→        for (const post of activePosts) {
 98→            if (post?.id) ids.add(post.id);
 99→        }
100→        return ids;
101→    }, [activePosts]);
102→
103→    const { centroidByUser } = useMemo(
104→        () => computeGalaxyCentroids(postArray),
105→        [postArray]
106→    );
107→
108→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
109→    const hashGalaxies = useMemo(() => {
110→        const seen = new Map();
111→        for (const post of postArray) {
112→            const uid = post.users?.id ?? post.user_id;
113→            if (!uid || seen.has(uid)) continue;
114→            const hash = userHomeCoords(uid);
115→            seen.set(uid, {
116→                userId: uid,
117→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
118→                x: hash.x,
119→                y: hash.y,
120→            });
121→        }
122→        return Array.from(seen.values());
123→    }, [postArray]);
124→
125→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
126→    const centroidTargets = useMemo(() => {
127→        const map = new Map();
128→        for (const c of centroids) {
129→            if (c.galaxy_x != null && c.galaxy_y != null) {
130→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
131→            }
132→        }
133→        return map;
134→    }, [centroids]);
135→
136→    // ── Gravity hook: animates galaxies + computes star pull offsets ─
137→    const {
138→        galaxyPositions,
139→        starPullOffsets,
140→        isSettled,
141→        galaxyEdges: effectiveGalaxyEdges,
142→        hasEmbeddingGravity,
143→    } = useCosmicGravity({
144→        galaxies: hashGalaxies,
145→        centroidTargets,
