147→        posts: postArray,
148→        starPulls,
149→        centroidByUser,
150→        activeSectorKeys,
151→        activePostIds,
152→        sectorSize: SECTOR_SIZE,
153→    });
154→
155→    // ── Render galaxies = hash galaxies with animated positions ──────
156→    const galaxies = useMemo(() => {
157→        return hashGalaxies.map(g => {
158→            const animated = galaxyPositions.get(g.userId);
159→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
160→        });
161→    }, [hashGalaxies, galaxyPositions]);
162→
163→    const getComputedStarPosition = useCallback((post) => {
164→        if (!post) return null;
165→
166→        const uid = post.users?.id ?? post.user_id;
167→        const hashGal = userHomeCoords(uid);
168→        const animGal = galaxyPositions.get(uid);
169→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
170→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
171→        const pull = starPullOffsets.get(post.id);
172→
173→        const baseX = post.universe_x ?? post.display_x;
174→        const baseY = post.universe_y ?? post.display_y;
175→        if (baseX == null || baseY == null) return null;
176→
177→        return {
178→            x: baseX + galDx + (pull?.dx ?? 0),
179→            y: baseY + galDy + (pull?.dy ?? 0),
180→        };
181→    }, [galaxyPositions, starPullOffsets]);
182→
183→    // Resolve logged-in user's galaxy target independently from viewport data.
184→    useEffect(() => {
185→        if (!userId) return;
186→        if (ownGalaxyLookupStartedRef.current) return;
187→
188→        ownGalaxyLookupStartedRef.current = true;
189→        let cancelled = false;
190→
191→        const resolveOwnGalaxyTarget = async () => {
192→            try {
193→                const { data, error } = await supabase
194→                    .from('galaxy_centroids')
195→                    .select('galaxy_x, galaxy_y')
196→                    .eq('user_id', userId)
197→                    .maybeSingle();
198→
199→                if (cancelled) return;
200→
201→                if (!error && data?.galaxy_x != null && data?.galaxy_y != null) {
202→                    setOwnGalaxyTarget({ x: data.galaxy_x, y: data.galaxy_y });
203→                    setHasOwnPosts(true);
204→                    return;
205→                }
206→            } catch (err) {
207→                console.warn('[universe] own centroid lookup failed:', err?.message || err);
208→            }
209→
210→            if (!cancelled) {
211→                setOwnGalaxyTarget(userHomeCoords(userId));
212→            }
213→        };
214→
215→        resolveOwnGalaxyTarget();
216→
217→        return () => {
218→            cancelled = true;
219→        };
220→    }, [userId]);
221→
222→    // Debounced fetch on camera/zoom change
223→    useEffect(() => {
224→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
225→
226→        fetchDebounceRef.current = setTimeout(async () => {
227→            const bounds = getViewportBounds();
228→            try {
229→                const result = await getUniversePosts(
230→                    bounds.minX,
231→                    bounds.maxX,
232→                    bounds.minY,
233→                    bounds.maxY,
234→                    200
235→                );
236→                if (result?.data) {
237→                    setPosts(prev => {
238→                        const next = new Map(prev);
239→                        for (const post of result.data) {
240→                            next.set(post.id, post);
241→                        }
242→                        return next;
243→                    });
244→                    if (userId && hasOwnPosts !== true) {
245→                        const ownsAny = result.data.some(p =>
246→                            (p.users?.id ?? p.user_id) === userId
247→                        );
248→                        if (ownsAny) setHasOwnPosts(true);
249→                    }
250→                }
251→                // Keep server gravity data as fallback when embeddings are absent in payload.
252→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
253→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
254→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
255→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
256→            } catch (err) {
