260→                    initialFetchResolvedRef.current = true;
261→                    setIsInitialLoading(false);
262→                }
263→            }
264→        }, 400);
265→
266→        return () => {
267→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
268→        };
269→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
270→
271→    const handleStarClick = useCallback((post) => {
272→        if (isFlying.current) return;
273→        setSelectedPost(post);
274→        setSelectedGalaxy(null);
275→        setGalaxyProfile(null);
276→
277→        const position = getComputedStarPosition(post);
