369→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
370→                }
371→            } catch (err) {
372→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
373→            }
374→        }, 1200);
375→
376→        return () => {
377→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
378→        };
379→    }, [isSettled, settledPayload]);
380→
381→    useEffect(() => {
382→        return () => {
383→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
384→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
385→        };
386→    }, []);
387→
388→    return (
389→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
390→            <button className={styles.backButton} onClick={() => navigate('/home')}>
391→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
392→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
393→                </svg>
394→                Back
395→            </button>
396→
397→            <div className={styles.coordsLabel}>
398→                {centerWorld.x}, {centerWorld.y}
399→            </div>
