  6→const TWO_PI = Math.PI * 2;
  7→const BREATH_PERIOD = 10000; // 10-second full cycle
  8→const ROTATION_SPEED = 0.002; // degrees per frame
  9→const BASE_RADIUS = 400;
 10→const RADIUS_PER_POST = 50;
 11→const MAX_EXTRA_POSTS = 4;
 12→
 13→/** Parse "#5f92ff" → { r, g, b } */
 14→const parseHex = (hex) => ({
 15→    r: parseInt(hex.slice(1, 3), 16),
 16→    g: parseInt(hex.slice(3, 5), 16),
 17→    b: parseInt(hex.slice(5, 7), 16),
 18→});
